// Four-state flow: Connect → Network → Approve → Action
// Button MUST disable + show spinner through block confirmation
<button
  disabled={isPending || isConfirming}
  onClick={handleWrite}
>
  {!isConnected        ? 'Connect Wallet'
  : chain.id !== TARGET ? 'Switch Network'
  : needsApproval      ? 'Approve Token'
  : isPending          ? <span className="loading loading-spinner" />
  :                      'Confirm Swap'}
</button>
